-- ❌ No index on the most common filter column
SELECT * FROM orders WHERE customer_id = 42;
-- → Seq Scan, reads all rows

-- ✅ Create an index on the filter column
CREATE INDEX idx_orders_customer ON orders(customer_id);
-- Now the same query uses an Index Scan, fetching only matching rows

-- ❌ Fails if the table already has rows — no default for existing data
ALTER TABLE orders ADD COLUMN shipping_carrier VARCHAR(50) NOT NULL;

-- ✅ Two-step migration:
-- Step 1: Add the column as nullable
ALTER TABLE orders ADD COLUMN shipping_carrier VARCHAR(50);

-- Step 2: Back-fill existing rows
UPDATE orders SET shipping_carrier = 'Unknown' WHERE shipping_carrier IS NULL;

-- Step 3: Now enforce NOT NULL
ALTER TABLE orders ALTER COLUMN shipping_carrier SET NOT NULL;
